class Solution:
    def longestCommonSubsequence(self, text1, text2):
        dp = [0] * (len(text2) + 1)
        for i in range(len(text1) - 1, -1, -1):
            prev = 0
            for j in range(len(text2) - 1, -1, -1):
                old = dp[j]
                dp[j] = 1 + prev if text1[i] == text2[j] else max(dp[j], dp[j + 1])
                prev = old
        return dp[0]
